def zip_strict(a, b):
    if len(a) != len(b):
        raise ValueError("len mismatch")
    return list(zip(a, b))

print(zip_strict([1, 2], [10, 20]))
try:
    zip_strict([1, 2, 3], [10, 20])
except ValueError as e:
    print("error", e)

